import fetch from "node-fetch";
import sharp from "sharp";
export async function fetchImage(src, allowPartial = false) {
    try {
        let imageBuffer;
        // supports partially loaded image reading
        const options = {};
        if (allowPartial) {
            options.failOn = "none";
        }
        if (src.startsWith("http")) {
            const response = await fetch(src);
            if (!response.ok) {
                throw new Error(`Failed to fetch image: ${response.statusText}`);
            }
            imageBuffer = Buffer.from(await response.arrayBuffer());
        }
        else {
            // Assume local file path
            imageBuffer = await sharp(src, options).toBuffer();
        }
        return sharp(imageBuffer, options);
    }
    catch {
        // console.error('Failed to fetch image:', error);
        return undefined;
    }
}
export function calculateImageSize({ maxWidth, maxHeight, originalAspectRatio, specifiedWidth, specifiedHeight, }) {
    // Both width and height specified
    if (specifiedWidth && specifiedHeight) {
        const width = Math.min(specifiedWidth, maxWidth);
        const height = Math.min(specifiedHeight, maxHeight);
        return { width: Math.round(width), height: Math.round(height) };
    }
    // Only width specified
    if (specifiedWidth) {
        let width = Math.min(specifiedWidth, maxWidth);
        let height = width / originalAspectRatio;
        if (height > maxHeight) {
            height = maxHeight;
            width = height * originalAspectRatio;
        }
        return { width: Math.round(width), height: Math.round(height) };
    }
    // Only height specified
    if (specifiedHeight) {
        let height = Math.min(specifiedHeight, maxHeight);
        let width = height * originalAspectRatio;
        if (width > maxWidth) {
            width = maxWidth;
            height = width / originalAspectRatio;
        }
        return { width: Math.round(width), height: Math.round(height) };
    }
    // No dimensions specified - scale to fit while maintaining aspect ratio
    let height = maxHeight;
    let width = height * originalAspectRatio;
    if (width > maxWidth) {
        width = maxWidth;
        height = width / originalAspectRatio;
    }
    if (height > maxHeight) {
        height = maxHeight;
        width = height * originalAspectRatio;
    }
    return { width: Math.round(width), height: Math.round(height) };
}
